`,"Progressively upgrading the game made the whole migration more manageable and put it into bite-sized chunks, which helped a lot with maintainability. For example, I had a bunch of utility functions sitting in my ",c.jsx(i.code,{children:"index.js"})," and didn't want to clutter my ",c.jsx(i.code,{children:"MyCanvas.tsx"}),", so I created a ",c.jsx(i.code,{children:"helpers.ts"})," file for these functions:"]}),`
`,c.jsx(i.pre,{children:c.jsx(i.code,{className:"language-tsx",children:`// helpers.ts

// draws the image but flips it horizontally
export function drawFlippedImage(
  context: CanvasRenderingContext2D,
  image: HTMLImageElement,
  x: number,
  y: number
) {
  context.save();
  context.translate(x + image.width / 2, 0);
  context.scale(-1, 1);
  context.translate(-(x + image.width / 2), 0);
  context.drawImage(image, Math.floor(x), Math.floor(y));
  context.restore();
}
`})}),`
